import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const InfoDriver = () => {
  const [trucks, setTrucks] = useState([]);
  const [search, setSearch] = useState(""); // ✅ state untuk search

  // ✅ Ambil data truck (dengan search)
  const fetchTrucks = (query = "") => {
    let url = "http://localhost:5000/api/trucks";
    if (query) {
      url += `?search=${query}`;
    }
    fetch(url)
      .then((res) => res.json())
      .then((data) => setTrucks(data))
      .catch((err) => console.error("Gagal mengambil data truck:", err));
  };

  useEffect(() => {
    fetchTrucks();
  }, []);

  // ✅ Handler saat search
  const handleSearch = (e) => {
    const value = e.target.value;
    setSearch(value);
    fetchTrucks(value);
  };

  return (
    <div
      className="flex min-h-screen bg-fixed bg-cover bg-center"
      style={{
        background: `linear-gradient(135deg, #43bfbf 0%, #076169 60%, #033c3b 100%)`
      }}
    >
      {/* Sidebar */}
      <div className="bg-black bg-opacity-70 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img src="/images/admin.png" alt="Admin Icon" className="rounded-full mb-2 w-16 h-16 object-cover" />
            <h2 className="font-semibold text-lg">Admin</h2>
          </div>
          <div className="space-y-6">
            <div className="bg-gray-700 rounded-lg p-3 text-center hover:bg-gray-600 transition">
              <Link to="/master-data" className="block hover:text-white">Master Data</Link>
            </div>
            <div className="bg-gray-700 rounded-lg p-3 text-center hover:bg-gray-600 transition">
              <Link to="/tracking" className="block hover:text-white">Tracking</Link>
            </div>
            <div className="bg-gray-700 rounded-lg p-3 text-center hover:bg-gray-600 transition">
              <Link to="/checkpoint" className="block hover:text-white">Checkpoint</Link>
            </div>
            <div className="bg-blue-700 rounded-lg p-3 text-center hover:bg-blue-600 transition">
              <Link to="/info-driver" className="block hover:text-white">Info Driver</Link>
            </div>
          </div>
        </div>
        <div className="space-y-6 mt-6">
          <div className="bg-gray-700 rounded-lg p-3 text-center hover:bg-gray-600 transition">
            <Link to="/settings" className="block hover:text-white">Settings</Link>
          </div>
          <div className="bg-gray-700 rounded-lg p-3 text-center hover:bg-gray-600 transition">
            <Link to="/logout" className="block hover:text-white">Logout</Link>
          </div>
          <div className="bg-indigo-700 rounded-lg p-3 text-center hover:bg-indigo-600 transition">
            <Link to="/timbang-muat" className="block hover:text-white">Timbang Muat</Link>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-6 bg-white bg-opacity-80 rounded-tl-3xl shadow-inner m-4">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold">Info Driver</h1>

          {/* ✅ Search Bar */}
          <input
            type="text"
            placeholder="Cari Truck / Driver / Plat Nomor..."
            value={search}
            onChange={handleSearch}
            className="border border-gray-400 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500 w-80"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {trucks.length === 0 ? (
            <p className="text-center text-gray-700 col-span-full">Tidak ada data truk yang tersedia.</p>
          ) : (
            trucks.map(truck => (
              <div key={truck.truckId} className="bg-white shadow-lg rounded-lg p-4">
                <img
                  src={truck.image_url || 'https://via.placeholder.com/300'}
                  alt="Truck"
                  className="w-full h-48 object-cover rounded mb-4"
                />
                <h2 className="text-lg font-semibold mb-1">Truck ID: {truck.truckId}</h2>
                <p className="text-sm mb-1">Tipe: <strong>{truck.truckType}</strong></p>
                <p className="text-sm mb-1">Driver: {truck.driver}</p>
                <p className="text-sm mb-1">Plat Nomor: <strong>{truck.plateNumber || '-'}</strong></p>
                <p className="text-sm mb-1">Status: <span className="italic">{truck.status}</span></p>
                <p className="text-sm mb-3">Tanggal: {truck.date ? truck.date.split('T')[0] : ''}</p>
                
                <Link
                  to={`/info-driver/${truck.truckId}`}
                  className="text-blue-600 font-medium hover:underline"
                >
                  Lihat lebih lengkap →
                </Link>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default InfoDriver;
